const contentType = pm.response.headers.get('Content-Type');
if (contentType === "application/xml") {
  var parseString = require('xml2js').parseString;
  parseString(pm.response.body, function(err, result) {
    if (err) {
      console.error('Error parsing XML:', err);
    } else {
      responseData = result;
    }
  });
} else {
  responseData = pm.response.json();
}
// Status code check with early exit
const expectedStatusCode = parseInt(pm.variables.get("statusCode"));
let statusMatches = true;
if (pm.variables.get("statusCode")) {
  statusMatches = (pm.response.code === expectedStatusCode);
  pm.test("Status code matches expected value", function() {
    pm.expect(pm.response.code).to.equal(expectedStatusCode);
  });
}

if (pm.response.code == 201 && statusMatches) {
  pm.test("employee created", function() {
    pm.expect(pm.response.status).to.be.eql("Created");
  });

}
if (pm.response.code == 400 && statusMatches) {
  pm.test("invalid input, object invalid", function() {
    pm.expect(pm.response.status).to.be.eql("Bad Request");
  });

}
if (pm.response.code == 409 && statusMatches) {
  pm.test("an existing employee already exists", function() {
    pm.expect(pm.response.status).to.be.eql("Conflict");
  });

}

